class Solution {
public:
    vector<int> beautifulIndices(string s, string a, string b, int k) {
        int n = s.size(), na = a.size(), nb = b.size();
        vector<int> res, posA, posB;

        auto kmp = [](const string& s, const string& pat) -> vector<int> {
            int m = pat.size();
            vector<int> lps(m, 0);
            for (int i = 1, len = 0; i < m; ) {
                if (pat[i] == pat[len]) lps[i++] = ++len;
                else if (len) len = lps[len - 1];
                else lps[i++] = 0;
            }
            vector<int> occ;
            for (int i = 0, j = 0; i < (int)s.size(); ) {
                if (s[i] == pat[j]) { ++i; ++j; }
                if (j == m) { occ.push_back(i - j); j = lps[j - 1]; }
                else if (i < (int)s.size() && s[i] != pat[j]) {
                    if (j) j = lps[j - 1];
                    else ++i;
                }
            }
            return occ;
        };

        posA = kmp(s, a);
        posB = kmp(s, b);

        int m = posB.size();
        for (int i : posA) {
            int l = lower_bound(posB.begin(), posB.end(), i - k) - posB.begin();
            int r = upper_bound(posB.begin(), posB.end(), i + k) - posB.begin();
            if (l < r) res.push_back(i);
        }
        return res;
    }
};
